const skipKeywords = [
  'for hire', 'logo design', 'seo services', 'social media manager',
  'content writer', 'virtual assistant', 'data entry', 'graphic designer',
  'video editor', 'copywriter', 'i am available', 'available for hire',
  'seeking clients', 'my services'
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const organicResults = data.organic_results || [];
  const queryType = data.search_parameters?.q?.includes('linkedin.com/jobs')
    ? 'linkedin_jobs' : 'linkedin_posts';

  for (const r of organicResults) {
    if (!r.link) continue;
    if (!r.link.includes('linkedin.com')) continue;

    const isPost = r.link.includes('/posts/') || r.link.includes('/pulse/');
    const isJob  = r.link.includes('/jobs/');
    if (!isPost && !isJob) continue;

    const id = 'li_' + (r.link || '').replace(/[^a-z0-9]/gi, '').substring(0, 80);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    let author = '';
    try {
      const urlParts = r.link.split('/');
      const inIdx = urlParts.indexOf('in');
      if (inIdx > -1) author = urlParts[inIdx + 1] || '';
      const companyIdx = urlParts.indexOf('company');
      if (companyIdx > -1) author = urlParts[companyIdx + 1] || '';
    } catch(e) {}

    results.push({ json: {
      title,
      description: snippet,
      source: queryType,
      source_url: r.link,
      source_id: id,
      posted_at: (function(){ try { const dt = r.date ? new Date(r.date) : null; return dt && !isNaN(dt.getTime()) ? dt.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: author.replace(/-/g, ' ').substring(0, 100),
      subreddit: '',
      upvotes: 0,
      num_comments: 0,
      flair_text: queryType === 'linkedin_jobs' ? 'Job/Contract' : 'Post',
      budget_text: ''
    }});
  }
}

if (results.length === 0) return [];
return results;

const posts = $input.all().map(i => i.json);
if (posts.length === 0) return [];

const apiKey = $env.GOOGLE_AI_API_KEY;
const BATCH_SIZE = 5;
const BETWEEN_BATCH_DELAY_MS = 1500;
const MAX_RETRIES = 2;
const CALL_TIMEOUT_MS = 120000;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, SaaS products, data pipelines.

These posts are from LinkedIn — found via Google search using site:linkedin.com.

IDEAL LEAD: Someone actively looking for a tech partner, dev team, or AI implementation help.

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 0.9+=clearly seeking AI/software partner | 0.7=business pain | 0.5=vague tech need | 0.0=irrelevant
2. budget_score: 1.0=$100K+ | 0.8=$50-100K | 0.6=$25-50K | 0.5=unknown but enterprise context | 0.2=small/unclear
3. urgency_score: 1.0=this week | 0.7=1 month | 0.4=exploring | 0.2=no urgency
4. win_probability: 0.8+=explicitly seeking agency/partner | 0.5=good fit unclear | 0.3=wants freelancer | 0.1=no fit

COMPANY EXTRACTION: Extract company name, founder name, website from LinkedIn URL or snippet. Never invent.`;

const callGeminiWithRetry = async (prompt) => {
  const body = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: 10000, temperature: 0.2, responseMimeType: 'application/json' },
  };
  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const result = await Promise.race([
        this.helpers.httpRequest({
          method: 'POST',
          url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
          body,
        }),
        new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), CALL_TIMEOUT_MS)),
      ]);
      return result;
    } catch(e) {
      if (String(e.message).includes('429') && attempt < MAX_RETRIES - 1) {
        await new Promise(r => setTimeout(r, Math.pow(2, attempt + 1) * 2000));
        continue;
      }
      throw e;
    }
  }
};

function computeScores(s) {
  const overall = Math.round((
    (s.relevance_score||0)*0.35 + (s.budget_score||0)*0.25 +
    (s.urgency_score||0)*0.15   + (s.win_probability||0)*0.25
  ) * 100) / 100;
  let alert_tier = 'discard';
  if (overall >= 0.85) alert_tier = 'instant';
  else if (overall >= 0.70) alert_tier = 'digest';
  else if (overall >= 0.30) alert_tier = 'dashboard';
  return { ...s, overall_score: overall, alert_tier };
}

function fallback() {
  return computeScores({ relevance_score:0.1,budget_score:0.1,urgency_score:0.1,win_probability:0.1,
    summary:'Parse error',industry:'Unknown',tags:[],reasoning:'error',
    estimated_budget_text:null,deadline_text:null,location:null,tech_stack:[],
    company_name:null,contact_info:null,lead_founder_name:null,lead_website:null });
}

function buildItem(post, s) {
  return { json: {
    title:                 post.title,
    description:           post.description,
    source:                post.source,
    source_url:            post.source_url,
    source_id:             post.source_id,
    posted_at:             post.posted_at,
    author:                post.author,
    subreddit:             '',
    upvotes:               0,
    num_comments:          0,
    relevance_score:       s.relevance_score,
    budget_score:          s.budget_score,
    urgency_score:         s.urgency_score,
    win_probability:       s.win_probability,
    overall_score:         s.overall_score,
    ai_summary:            s.summary,
    industry:              s.industry,
    ai_tags:               s.tags || [],
    ai_reasoning:          s.reasoning,
    estimated_budget_text: s.estimated_budget_text,
    deadline_text:         s.deadline_text,
    location:              s.location,
    tech_stack:            s.tech_stack || [],
    lead_founder:          s.lead_founder_name || null,
    lead_company:          s.company_name || null,
    lead_website:          s.lead_website || null,
    lead_contact:          s.contact_info || null,
    lead_score:            Math.round(s.overall_score * 10),
    alert_tier:            s.alert_tier,
    discovered_at:         new Date().toISOString(),
    status:                'new',
    outreach_draft:        '',
    hunter_name:           '',
    hunter_email:          '',
    hunter_title:          '',
    hunter_company:        ''
  }};
}

const results = [];
for (let i = 0; i < posts.length; i += BATCH_SIZE) {
  const batch = posts.slice(i, i + BATCH_SIZE);
  const postsBlock = batch.map((p, idx) =>
    'POST ' + (idx+1) + ':\nTitle: ' + p.title +
    '\nSource Type: ' + (p.source === 'linkedin_jobs' ? 'LinkedIn Job/Contract' : 'LinkedIn Post') +
    '\nURL: ' + p.source_url +
    '\nSnippet: ' + (p.description || '').substring(0, 600)
  ).join('\n\n---\n\n');

  const schema = '{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"2-3 sentences","industry":"FinTech/HealthTech/SaaS/Manufacturing/General","tags":[],"reasoning":"brief","estimated_budget_text":null,"deadline_text":null,"location":null,"tech_stack":[],"company_name":null,"contact_info":null,"lead_founder_name":null,"lead_website":null}';
  const prompt = SYSTEM_PROMPT + '\n\nScore ALL ' + batch.length + ' posts. Return ONLY a valid JSON array with exactly ' + batch.length + ' objects. Each: ' + schema + '\n\n' + postsBlock;

  let batchScores = null;
  try {
    const respRaw = await callGeminiWithRetry(prompt);
    const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
    const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
    const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
    const match = cleaned.match(/\[[\s\S]*\]/);
    if (match) {
      const parsed = JSON.parse(match[0]);
      if (Array.isArray(parsed) && parsed.length > 0) batchScores = parsed;
    }
  } catch(e) {}

  for (let j = 0; j < batch.length; j++) {
    const s = batchScores && batchScores[j] ? computeScores(batchScores[j]) : fallback();
    results.push(buildItem(batch[j], s));
  }
  if (i + BATCH_SIZE < posts.length) await new Promise(r => setTimeout(r, BETWEEN_BATCH_DELAY_MS));
}

return results;

